	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
)

// These tests pin the routing-unify-1 contract (ddx-c7081f89): the
// server worker's escalation predicate must match the CLI's --escalate
// opt-in semantics. Tier-ladder escalation (cheap → standard → smart)
// fires only when spec.Escalate is true AND the operator has not pinned
// Harness or Model. Pinning either field always bypasses escalation.
//
// Equivalent CLI predicate:
//
//	cli/cmd/agent_cmd.go:runAgentExecuteLoop
//	  escalationEnabled := escalate && harness == "" && model == ""
//
// Equivalent server predicate (after this bead):
//
//	cli/internal/server/workers.go:runWorker
//	  escalationEnabled := escalationEnabledForSpec(spec)

// TestEscalationEnabledForSpec pins the predicate that gates whether
// the server worker iterates the tier ladder. The contract is: only
// when the operator opts in (spec.Escalate == true) AND has not pinned
// a harness or model. Any harness/model pin always wins, regardless of
// the Escalate flag.
func TestEscalationEnabledForSpec(t *testing.T) {
	cases := []struct {
		name string
		spec ExecuteLoopWorkerSpec
		want bool
	}{
		{"default zero-value: escalation off", ExecuteLoopWorkerSpec{}, false},
		{"escalate=false even with no pin: off", ExecuteLoopWorkerSpec{Escalate: false}, false},
		{"escalate=true, no pin: on", ExecuteLoopWorkerSpec{Escalate: true}, true},
		{"escalate=true with harness pin: off (pin wins)", ExecuteLoopWorkerSpec{Escalate: true, Harness: "claude"}, false},
		{"escalate=true with model pin: off (pin wins)", ExecuteLoopWorkerSpec{Escalate: true, Model: "qwen/qwen3.6"}, false},
		{"escalate=true with both pins: off", ExecuteLoopWorkerSpec{Escalate: true, Harness: "claude", Model: "claude-opus-4-7"}, false},
		{"escalate=false with harness pin: off", ExecuteLoopWorkerSpec{Harness: "claude"}, false},
		{"escalate=false with model pin: off", ExecuteLoopWorkerSpec{Model: "qwen/qwen3.6"}, false},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			if got := escalationEnabledForSpec(tc.spec); got != tc.want {
				t.Errorf("escalationEnabledForSpec(%+v) = %v, want %v", tc.spec, got, tc.want)
			}
		})
	}
}

// fakeTierAttempt is a stub for the singleTierAttempt closure inside
// runWorker. It records the (harness, model) it was called with and
// returns a pre-canned report. Used to exercise the escalation flow
// in isolation from agent.ExecuteBeadWithConfig.
type fakeTierAttempt struct {
	calls atomic.Int32
	last  struct {
		harness, provider, model, tier string
	}
	report agent.ExecuteBeadReport
}

func (f *fakeTierAttempt) run(_ context.Context, beadID string, tier escalation.ModelTier, harness, provider, model string) (agent.ExecuteBeadReport, error) {
	f.calls.Add(1)
	f.last.harness = harness
	f.last.provider = provider
	f.last.model = model
	f.last.tier = string(tier)
	report := f.report
	report.BeadID = beadID
	return report, nil
}

// mirrorEscalationExecutor wraps a fake singleTierAttempt with the
// same escalation gate as the production runWorker closure
// (cli/internal/server/workers.go). It mirrors only the default-path
// branch: when escalationEnabled is false, the inner attempt runs once
// with the spec's pinned (harness, model). When true, the executor
// consults agent.ResolveProfileLadder — the same ladder helper the
// production tier loop calls — so the call counter advances.
//
// This is a "mirror" test pattern, identical to the one used by
// TestWorkerExecutorCostCap_StopsAfterCap in workers_costcap_test.go
// (the production closure is built inline and cannot be invoked
// directly).
func mirrorEscalationExecutor(spec ExecuteLoopWorkerSpec, routingCfg *config.RoutingConfig, profile string, attempt *fakeTierAttempt) func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
	escalationEnabled := escalationEnabledForSpec(spec)
	return func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		if !escalationEnabled {
			return attempt.run(ctx, beadID, "", spec.Harness, spec.Provider, spec.Model)
		}
		_ = agent.ResolveProfileLadder(routingCfg, profile, spec.MinTier, spec.MaxTier)
		// In production the loop iterates tiers and dispatches an
		// attempt per tier; the call-counter assertion is the load-
		// bearing claim, so we stop after the ladder lookup.
		return attempt.run(ctx, beadID, "", "", "", "")
	}
}

// TestBeadExecutorEscalateFalseSkipsTierLadder is the load-bearing
// AC #4 assertion: with the default spec (Escalate=false), the worker
// executor does NOT consult agent.ResolveProfileLadder — there is no
// tier loop, and the dispatched attempt uses spec.Harness / spec.Model
// directly (both "" on the default path).
func TestBeadExecutorEscalateFalseSkipsTierLadder(t *testing.T) {
	agent.ResetRoutingCallCounters()
	defer agent.ResetRoutingCallCounters()

	attempt := &fakeTierAttempt{
		report: agent.ExecuteBeadReport{Status: agent.ExecuteBeadStatusSuccess},
	}
	exec := mirrorEscalationExecutor(ExecuteLoopWorkerSpec{}, nil, "default", attempt)

	if _, err := exec(context.Background(), "ddx-test"); err != nil {
		t.Fatalf("executor: %v", err)
	}
	if got := attempt.calls.Load(); got != 1 {
		t.Errorf("inner attempt call count = %d, want 1", got)
	}
	if got := agent.ResolveProfileLadderCallCount(); got != 0 {
		t.Errorf("ResolveProfileLadder must NOT be called when Escalate=false; got %d", got)
	}
}

// TestBeadExecutorEscalateTrueWalksTierLadder is the inverse of the
// AC: with Escalate=true and no harness/model pin, the executor
// consults agent.ResolveProfileLadder so the tier loop can iterate.
func TestBeadExecutorEscalateTrueWalksTierLadder(t *testing.T) {
	agent.ResetRoutingCallCounters()
	defer agent.ResetRoutingCallCounters()

	attempt := &fakeTierAttempt{
		report: agent.ExecuteBeadReport{Status: agent.ExecuteBeadStatusSuccess},
	}
	exec := mirrorEscalationExecutor(ExecuteLoopWorkerSpec{Escalate: true}, nil, "default", attempt)

	if _, err := exec(context.Background(), "ddx-test"); err != nil {
		t.Fatalf("executor: %v", err)
	}
	if got := agent.ResolveProfileLadderCallCount(); got == 0 {
		t.Errorf("ResolveProfileLadder must be called when Escalate=true; got 0")
	}
}

// TestBeadExecutorOperatorPinBypassesEscalation pins AC #5: when an
// operator sets --harness or --model, the tier ladder is bypassed
// even if --escalate is set. This preserves the existing operator
// override behavior and matches the CLI predicate exactly.
func TestBeadExecutorOperatorPinBypassesEscalation(t *testing.T) {
	agent.ResetRoutingCallCounters()
	defer agent.ResetRoutingCallCounters()

	cases := []struct {
		name string
		spec ExecuteLoopWorkerSpec
	}{
		{"escalate + harness pin", ExecuteLoopWorkerSpec{Escalate: true, Harness: "claude"}},
		{"escalate + model pin", ExecuteLoopWorkerSpec{Escalate: true, Model: "qwen/qwen3.6"}},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			agent.ResetRoutingCallCounters()
			attempt := &fakeTierAttempt{
				report: agent.ExecuteBeadReport{Status: agent.ExecuteBeadStatusSuccess},
			}
			exec := mirrorEscalationExecutor(tc.spec, nil, "default", attempt)
			if _, err := exec(context.Background(), "ddx-test"); err != nil {
				t.Fatalf("executor: %v", err)
			}
			if got := agent.ResolveProfileLadderCallCount(); got != 0 {
				t.Errorf("operator pin must bypass escalation; ResolveProfileLadder was called %d time(s)", got)
			}
			if got := attempt.calls.Load(); got != 1 {
				t.Errorf("inner attempt call count = %d, want 1", got)
			}
		})
	}
}

